def build_prompt(context, goal, constraints, format):
    return (
        f"context: {context}\n"
        f"goal: {goal}\n"
        f"constraints: {constraints}\n"
        f"format: {format}"
    )

print(build_prompt(
    "fastapi route file",
    "add delete handler",
    "use existing pool",
    "diff only",
))

